query:
SELECT f.id, f.name, f.userId, f.orgId, u.role as userRole
FROM facilities f
JOIN users u ON f.userId = u.id
WHERE f.name LIKE '%CofST%' OR f.name LIKE '%Orchid%';

SELECT * FROM org_members WHERE userId = 1;

